diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index d9f53c4146c2..d53122b630b1 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -3265,6 +3265,24 @@ bool LoopVectorizationCostModel::memoryInstructionCanBeWidened(
   // In order to be widened, the pointer should be consecutive, first of all.
   if (!Legal->isConsecutivePtr(ScalarTy, Ptr))
     return false;
+  //* Avoid widening if the address computation depends on a predicated instruction. */
+  {
+    auto DependsOnPredicatedInst = [this](Value *V) {
+      SmallVector<Value *, 8> Worklist; SmallPtrSet<Value *, 16> Visited;
+      Worklist.push_back(V);
+      while (!Worklist.empty()) {
+        Value *Cur = Worklist.pop_back_val();
+        if (!Visited.insert(Cur).second) continue;
+        if (auto *CurI = dyn_cast<Instruction>(Cur)) {
+          if (isPredicatedInst(CurI)) return true;
+          for (Value *Op : CurI->operands()) Worklist.push_back(Op);
+        }
+      }
+      return false;
+    };
+    if (DependsOnPredicatedInst(Ptr))
+      return false;
+  }

   // If the instruction is a store located in a predicated block, it will be
   // scalarized.
